FROM jsonb_to_recordset('[{"id": "cap-109-chinese-001", "exam_id": "cap", "subject_id": "sub-cap-chinese", "paper_id": "cap-109-chinese", "question_type": "single_choice", "question_text": "根據這張圖表，下列何者的症狀最可能是中暑？", "options": ["冒汗而體溫正常的小健", "體溫過高不出汗的小康", "大量流汗虛弱頭暈的小平", "心跳加速體溫正常的小安"], "correct_answer": 1, "correct_answer_json": null, "parent_question_id": null, "media": null, "source": "official", "source_meta": {"parser_version": "cap_v0.1", "merger_version": "cap_merger_v0.2", "parsed_at": "2026-04-25T19:26:39+00:00", "source_pdf_sha1": "17ed74d9cea4", "answer_pdf_sha1": "64e8d2b7d3a1", "flags": [], "parse_confidence": 1.0, "original_question_number": 1, "raw_text": "1.\n\n\n\n\n     根據這張圖表，下列何者的症狀最可能是中暑？\n     (A)冒汗而體溫正常的小健\n     (B)體溫過高不出汗的小康\n     (C)大量流汗虛弱頭暈的小平\n     (D)心跳加速體溫正常的小安\n"}, "is_active": true, "auto_gradable": true, "difficulty": 3, "explanation": null}, {"id": "cap-109-chinese-002", "exam_id": "cap", "subject_id": "sub-cap-chinese", "paper_id": "cap-109-chinese", "question_type": "single_choice", "question_text": "「寧可讓學得快的人等，也不能讓不會的人繼續不會。」下列何者最符合這句話\n所強調的教育理念？", "options": ["強化資優教育，培養菁英", "提倡忍讓，加強品格教育", "視學生資質，給予適當教導", "無論良與莠，一個都不放棄"], "correct_answer": 3, "correct_answer_json": null, "parent_question_id": null, "media": null, "source": "official", "source_meta": {"parser_version": "cap_v0.1", "merger_version": "cap_merger_v0.2", "parsed_at": "2026-04-25T19:26:39+00:00", "source_pdf_sha1": "17ed74d9cea4", "answer_pdf_sha1": "64e8d2b7d3a1", "flags": [], "parse_confidence": 1.0, "original_question_number": 2, "raw_text": "2.   「寧可讓學得快的人等，也不能讓不會的人繼續不會。」下列何者最符合這句話\n     所強調的教育理念？\n     (A)強化資優教育，培養菁英\n     (B)提倡忍讓，加強品格教育\n     (C)視學生資質，給予適當教導\n     (D)無論良與莠，一個都不放棄\n"}, "is_active": true, "auto_gradable": true, "difficulty": 3, "explanation": null}, {"id": "cap-109-chinese-003", "exam_id": "cap", "subject_id": "sub-cap-chinese", "paper_id": "cap-109-chinese", "question_type": "single_choice", "question_text": "人生何嘗不像一場競賽。跑得慢的人有些會怨天尤人，一路上窩囊委屈；\n有的卻抱著龜兔賽跑的精神，努力不懈直到終點。而那些跑得快的也不見得永\n遠領先，有的後繼無力被人超前，有的半路摔倒一蹶不起，選擇放棄。因此，\n________________________ 。\n根據文意，畫線處填入下列何者最恰當？", "options": ["人生的競賽往往是暗潮洶湧的", "臺前風光是背後汗水累積而成", "勝敗皆由天定，無須怨天尤人", "堅持到底的人才是最後的贏家"], "correct_answer": 3, "correct_answer_json": null, "parent_question_id": null, "media": null, "source": "official", "source_meta": {"parser_version": "cap_v0.1", "merger_version": "cap_merger_v0.2", "parsed_at": "2026-04-25T19:26:39+00:00", "source_pdf_sha1": "17ed74d9cea4", "answer_pdf_sha1": "64e8d2b7d3a1", "flags": [], "parse_confidence": 1.0, "original_question_number": 3, "raw_text": "3.       人生何嘗不像一場競賽。跑得慢的人有些會怨天尤人，一路上窩囊委屈；\n     有的卻抱著龜兔賽跑的精神，努力不懈直到終點。而那些跑得快的也不見得永\n     遠領先，有的後繼無力被人超前，有的半路摔倒一蹶不起，選擇放棄。因此，\n     ________________________ 。\n     根據文意，畫線處填入下列何者最恰當？\n     (A)人生的競賽往往是暗潮洶湧的\n     (B)臺前風光是背後汗水累積而成\n     (C)勝敗皆由天定，無須怨天尤人\n     (D)堅持到底的人才是最後的贏家\n"}, "is_active": true, "auto_gradable": true, "difficulty": 3, "explanation": null}, {"id": "cap-109-chinese-004", "exam_id": "cap", "subject_id": "sub-cap-chinese", "paper_id": "cap-109-chinese", "question_type": "single_choice", "question_text": "「野生動物隨著環境會發展出新的生活方式。城市中的灰色松鼠比鄉下的較快\n對威脅產生反應，牠們不吱吱叫驅趕敵人，而是垂下尾巴來警示敵人。」根\n據這段文字，下列敘述何者最不恰當？", "options": ["城市松鼠會因環境改變毛色", "城市松鼠會以垂下尾巴示警", "鄉下松鼠對威脅的反應較慢", "鄉下松鼠以吱吱叫驅趕敵人"], "correct_answer": 0, "correct_answer_json": null, "parent_question_id": null, "media": null, "source": "official", "source_meta": {"parser_version": "cap_v0.1", "merger_version": "cap_merger_v0.2", "parsed_at": "2026-04-25T19:26:39+00:00", "source_pdf_sha1": "17ed74d9cea4", "answer_pdf_sha1": "64e8d2b7d3a1", "flags": [], "parse_confidence": 1.0, "original_question_number": 4, "raw_text": "4. 「野生動物隨著環境會發展出新的生活方式。城市中的灰色松鼠比鄉下的較快\n   對威脅產生反應，牠們不吱吱叫驅趕敵人，而是垂下尾巴來警示敵人。」根\n   據這段文字，下列敘述何者最不恰當？\n   (A)城市松鼠會因環境改變毛色\n   (B)城市松鼠會以垂下尾巴示警\n   (C)鄉下松鼠對威脅的反應較慢\n   (D)鄉下松鼠以吱吱叫驅趕敵人\n"}, "is_active": true, "auto_gradable": true, "difficulty": 3, "explanation": null}, {"id": "cap-109-chinese-005", "exam_id": "cap", "subject_id": "sub-cap-chinese", "paper_id": "cap-109-chinese", "question_type": "single_choice", "question_text": "關於這則貼文與留言，下列解讀何者最恰當？", "options": ["小畢認為善惡終有報", "阿文的想法傾向樂觀", "凱哥同意小畢的觀點", "小安的看法近於小畢"], "correct_answer": 3, "correct_answer_json": null, "parent_question_id": null, "media": null, "source": "official", "source_meta": {"parser_version": "cap_v0.1", "merger_version": "cap_merger_v0.2", "parsed_at": "2026-04-25T19:26:39+00:00", "source_pdf_sha1": "17ed74d9cea4", "answer_pdf_sha1": "64e8d2b7d3a1", "flags": [], "parse_confidence": 1.0, "original_question_number": 5, "raw_text": "5.                 關於這則貼文與留言，下列解讀何者最恰當？\n                   (A)小畢認為善惡終有報\n                   (B)阿文的想法傾向樂觀\n                   (C)凱哥同意小畢的觀點\n                   (D)小安的看法近於小畢\n\n\n\n"}, "is_active": true, "auto_gradable": true, "difficulty": 3, "explanation": null}, {"id": "cap-109-chinese-006", "exam_id": "cap", "subject_id": "sub-cap-chinese", "paper_id": "cap-109-chinese", "question_type": "single_choice", "question_text": "下列文句，何者詞語使用最恰當？", "options": ["酒後不開車，未免發生事故", "見到故居破敗，不免有些傷感", "他毫無商量餘地，避免不近人情", "他決心改正遲到毛病，難免受處罰"], "correct_answer": 1, "correct_answer_json": null, "parent_question_id": null, "media": null, "source": "official", "source_meta": {"parser_version": "cap_v0.1", "merger_version": "cap_merger_v0.2", "parsed_at": "2026-04-25T19:26:39+00:00", "source_pdf_sha1": "17ed74d9cea4", "answer_pdf_sha1": "64e8d2b7d3a1", "flags": [], "parse_confidence": 1.0, "original_question_number": 6, "raw_text": "6.   下列文句，何者詞語使用最恰當？\n     (A)酒後不開車，未免發生事故\n     (B)見到故居破敗，不免有些傷感\n     (C)他毫無商量餘地，避免不近人情\n     (D)他決心改正遲到毛病，難免受處罰\n"}, "is_active": true, "auto_gradable": true, "difficulty": 3, "explanation": null}, {"id": "cap-109-chinese-007", "exam_id": "cap", "subject_id": "sub-cap-chinese", "paper_id": "cap-109-chinese", "question_type": "single_choice", "question_text": "「宋朝根據房門的位置來確定座次貴賤。面向房門的座位最尊貴，若無長輩就\n讓它空著。長輩左手的那邊是主人位，右手邊是客人位，長輩對面是副陪的位\n置，坐在那裡方便傳菜斟酒。」小秦到朋友大蘇家作客，爸爸老蘇和弟弟小蘇\n同席，下列圖示座次，何者最符合這段文字的敘述？", "options": ["", "", "", ""], "correct_answer": 1, "correct_answer_json": null, "parent_question_id": null, "media": null, "source": "official", "source_meta": {"parser_version": "cap_v0.1", "merger_version": "cap_merger_v0.2", "parsed_at": "2026-04-25T19:26:39+00:00", "source_pdf_sha1": "17ed74d9cea4", "answer_pdf_sha1": "64e8d2b7d3a1", "flags": ["option_incomplete", "option_image"], "parse_confidence": 0.4, "original_question_number": 7, "raw_text": "7. 「宋朝根據房門的位置來確定座次貴賤。面向房門的座位最尊貴，若無長輩就\n    讓它空著。長輩左手的那邊是主人位，右手邊是客人位，長輩對面是副陪的位\n    置，坐在那裡方便傳菜斟酒。」小秦到朋友大蘇家作客，爸爸老蘇和弟弟小蘇\n    同席，下列圖示座次，何者最符合這段文字的敘述？\n     (A)             (B)\n\n\n\n\n     (C)             (D)\n\n\n\n\n"}, "is_active": false, "auto_gradable": false, "difficulty": 3, "explanation": null}, {"id": "cap-109-chinese-008", "exam_id": "cap", "subject_id": "sub-cap-chinese", "paper_id": "cap-109-chinese", "question_type": "single_choice", "question_text": "「和你的詩作凍結在一起或因某幾首詩而大獲激賞是痛苦的事。真正的生命存\n在於寫作當中，而非經年累月一再朗讀同樣的幾首詩。我們不斷的需要有新\n的洞察和觀點，我們的生活也非一成不變。你無法在幾首詩裡便挖掘出永恆\n不滅的真理。」就創作而言，這段文字的觀點，與下列何者最接近？", "options": ["持續寫作，就能成就不朽的巨作", "創作應力求突破窠臼，不斷創新", "師法各家作品，塑造自我的風格", "嘗試不同的生活，激發創作靈感"], "correct_answer": 1, "correct_answer_json": null, "parent_question_id": null, "media": null, "source": "official", "source_meta": {"parser_version": "cap_v0.1", "merger_version": "cap_merger_v0.2", "parsed_at": "2026-04-25T19:26:39+00:00", "source_pdf_sha1": "17ed74d9cea4", "answer_pdf_sha1": "64e8d2b7d3a1", "flags": [], "parse_confidence": 1.0, "original_question_number": 8, "raw_text": "8. 「和你的詩作凍結在一起或因某幾首詩而大獲激賞是痛苦的事。真正的生命存\n   在於寫作當中，而非經年累月一再朗讀同樣的幾首詩。我們不斷的需要有新\n   的洞察和觀點，我們的生活也非一成不變。你無法在幾首詩裡便挖掘出永恆\n   不滅的真理。」就創作而言，這段文字的觀點，與下列何者最接近？\n   (A)持續寫作，就能成就不朽的巨作  (B)創作應力求突破窠臼，不斷創新\n   (C)師法各家作品，塑造自我的風格 (D)嘗試不同的生活，激發創作靈感\n"}, "is_active": true, "auto_gradable": true, "difficulty": 3, "explanation": null}, {"id": "cap-109-chinese-009", "exam_id": "cap", "subject_id": "sub-cap-chinese", "paper_id": "cap-109-chinese", "question_type": "single_choice", "question_text": "「朋友曾問過我一個問題□失去視力和失去聽力，害怕哪一項？我思考許久，\n最後坦承：什麼也不想失去。眼睛的世界那樣可喜，聽見的聲音卻更像一種\n心靈的共振□閉上眼睛也能讓情節自己呼應。我不能放棄兩者□也不願被兩\n者放棄。」這段文字空格處的標點符號，依序填入下列何者最恰當？", "options": ["， 。 ；", "， ； 、", "： ， ，", "： 。 、"], "correct_answer": 2, "correct_answer_json": null, "parent_question_id": null, "media": null, "source": "official", "source_meta": {"parser_version": "cap_v0.1", "merger_version": "cap_merger_v0.2", "parsed_at": "2026-04-25T19:26:39+00:00", "source_pdf_sha1": "17ed74d9cea4", "answer_pdf_sha1": "64e8d2b7d3a1", "flags": [], "parse_confidence": 1.0, "original_question_number": 9, "raw_text": "9. 「朋友曾問過我一個問題□失去視力和失去聽力，害怕哪一項？我思考許久，\n   最後坦承：什麼也不想失去。眼睛的世界那樣可喜，聽見的聲音卻更像一種\n   心靈的共振□閉上眼睛也能讓情節自己呼應。我不能放棄兩者□也不願被兩\n   者放棄。」這段文字空格處的標點符號，依序填入下列何者最恰當？\n   (A)， 。 ； (B)， ； 、 (C)： ， ， (D)： 。 、\n"}, "is_active": true, "auto_gradable": true, "difficulty": 3, "explanation": null}, {"id": "cap-109-chinese-010", "exam_id": "cap", "subject_id": "sub-cap-chinese", "paper_id": "cap-109-chinese", "question_type": "single_choice", "question_text": "「此事關係重大，一定要在時限內完成，不得有誤。」句中「得」字的字義與\n下列何者相同？", "options": ["「得」過且過", "相「得」益彰", "忘懷「得」失", "洋洋自「得」"], "correct_answer": 0, "correct_answer_json": null, "parent_question_id": null, "media": null, "source": "official", "source_meta": {"parser_version": "cap_v0.1", "merger_version": "cap_merger_v0.2", "parsed_at": "2026-04-25T19:26:39+00:00", "source_pdf_sha1": "17ed74d9cea4", "answer_pdf_sha1": "64e8d2b7d3a1", "flags": [], "parse_confidence": 1.0, "original_question_number": 10, "raw_text": "10. 「此事關係重大，一定要在時限內完成，不得有誤。」句中「得」字的字義與\n    下列何者相同？\n    (A)「得」過且過 (B)相「得」益彰 (C)忘懷「得」失 (D)洋洋自「得」\n"}, "is_active": true, "auto_gradable": true, "difficulty": 3, "explanation": null}, {"id": "cap-109-chinese-011", "exam_id": "cap", "subject_id": "sub-cap-chinese", "paper_id": "cap-109-chinese", "question_type": "single_choice", "question_text": "「杲杲1冬日出，照我屋南隅。負暄閉目坐，和氣生肌膚。初似飲醇醪2，又如\n蟄者蘇。外融百骸暢，中適一念無。曠然忘所在，心與虛空俱。」關於這首\n詩的分析，下列敘述何者正確？\n", "options": ["本詩為一韻到底的五言律詩     1.杲杲：日光明亮。杲，音ㄍㄠˇ", "以飲美酒比喻午後昏昏欲睡的狀態  2.醇醪：美酒。醪，音ㄌㄠˊ", "描寫層次由外而內，鋪陳歡聚之樂", "呈現冬日曬太陽時，閒適自得的心境"], "correct_answer": 3, "correct_answer_json": null, "parent_question_id": null, "media": null, "source": "official", "source_meta": {"parser_version": "cap_v0.1", "merger_version": "cap_merger_v0.2", "parsed_at": "2026-04-25T19:26:39+00:00", "source_pdf_sha1": "17ed74d9cea4", "answer_pdf_sha1": "64e8d2b7d3a1", "flags": [], "parse_confidence": 1.0, "original_question_number": 11, "raw_text": "11. 「杲杲1冬日出，照我屋南隅。負暄閉目坐，和氣生肌膚。初似飲醇醪2，又如\n    蟄者蘇。外融百骸暢，中適一念無。曠然忘所在，心與虛空俱。」關於這首\n    詩的分析，下列敘述何者正確？\n                        \n    (A)本詩為一韻到底的五言律詩     1.杲杲：日光明亮。杲，音ㄍㄠˇ\n    (B)以飲美酒比喻午後昏昏欲睡的狀態  2.醇醪：美酒。醪，音ㄌㄠˊ\n    (C)描寫層次由外而內，鋪陳歡聚之樂\n    (D)呈現冬日曬太陽時，閒適自得的心境\n"}, "is_active": true, "auto_gradable": true, "difficulty": 3, "explanation": null}, {"id": "cap-109-chinese-012", "exam_id": "cap", "subject_id": "sub-cap-chinese", "paper_id": "cap-109-chinese", "question_type": "single_choice", "question_text": "林懷民悼念雲門舞集燈光設計師張贊桃：「你的燈光輕聲細語，除非必要，\n絕不大聲號叫。典雅寫意，呼吸般起落的燈光成為雲門的特色。臺灣舞評\n少，評舞也不提燈光。國外談雲門不讚美你的舞評極少。他們說你是大師，\n你一笑置之。等到有人說，你的燈光讓他想起林布蘭1，你就如逢知音，開懷\n咧口笑了。那幾年，你吃林布蘭睡林布蘭，到了美術館，幾乎把鼻子貼到他\n的畫作上。」根據這段文字，下列關於張贊桃燈光設計的敘述何者正確？", "options": ["以林布蘭的畫當作舞臺背景", "作品在臺灣舞評界享有盛名    1.林布蘭：巴洛克美術的代表畫家", "能恰如其分的襯托舞臺演出", "國外舞評極少注意他的設計"], "correct_answer": 2, "correct_answer_json": null, "parent_question_id": null, "media": null, "source": "official", "source_meta": {"parser_version": "cap_v0.1", "merger_version": "cap_merger_v0.2", "parsed_at": "2026-04-25T19:26:39+00:00", "source_pdf_sha1": "17ed74d9cea4", "answer_pdf_sha1": "64e8d2b7d3a1", "flags": [], "parse_confidence": 1.0, "original_question_number": 12, "raw_text": "12. 林懷民悼念雲門舞集燈光設計師張贊桃：「你的燈光輕聲細語，除非必要，\n    絕不大聲號叫。典雅寫意，呼吸般起落的燈光成為雲門的特色。臺灣舞評\n    少，評舞也不提燈光。國外談雲門不讚美你的舞評極少。他們說你是大師，\n    你一笑置之。等到有人說，你的燈光讓他想起林布蘭1，你就如逢知音，開懷\n    咧口笑了。那幾年，你吃林布蘭睡林布蘭，到了美術館，幾乎把鼻子貼到他\n    的畫作上。」根據這段文字，下列關於張贊桃燈光設計的敘述何者正確？\n    (A)以林布蘭的畫當作舞臺背景\n    (B)作品在臺灣舞評界享有盛名   \n                      1.林布蘭：巴洛克美術的代表畫家\n    (C)能恰如其分的襯托舞臺演出\n    (D)國外舞評極少注意他的設計\n"}, "is_active": true, "auto_gradable": true, "difficulty": 3, "explanation": null}, {"id": "cap-109-chinese-013", "exam_id": "cap", "subject_id": "sub-cap-chinese", "paper_id": "cap-109-chinese", "question_type": "single_choice", "question_text": "「讀完一千本書的價值，並不多於犁過千片田地；能夠對一幅畫作出適當的描\n寫，其價值並不多於找出一輛故障摩托車的毛病。」這句話的意旨，與下列\n何者最接近？", "options": ["精神勝於物質", "實用重於美觀", "勞力者不遜於勞心者", "拿筆者比不上拿鋤者"], "correct_answer": 2, "correct_answer_json": null, "parent_question_id": null, "media": null, "source": "official", "source_meta": {"parser_version": "cap_v0.1", "merger_version": "cap_merger_v0.2", "parsed_at": "2026-04-25T19:26:39+00:00", "source_pdf_sha1": "17ed74d9cea4", "answer_pdf_sha1": "64e8d2b7d3a1", "flags": [], "parse_confidence": 1.0, "original_question_number": 13, "raw_text": "13. 「讀完一千本書的價值，並不多於犁過千片田地；能夠對一幅畫作出適當的描\n    寫，其價值並不多於找出一輛故障摩托車的毛病。」這句話的意旨，與下列\n    何者最接近？\n    (A)精神勝於物質       (B)實用重於美觀\n    (C)勞力者不遜於勞心者    (D)拿筆者比不上拿鋤者\n"}, "is_active": true, "auto_gradable": true, "difficulty": 3, "explanation": null}, {"id": "cap-109-chinese-014", "exam_id": "cap", "subject_id": "sub-cap-chinese", "paper_id": "cap-109-chinese", "question_type": "single_choice", "question_text": "「『個人資料保護法』強調，須經當事人同意才能蒐集與處理其個資，而且\n僅能用於特定目的。眾人為使用地圖導航或方便聯繫，只能同意交付行蹤與\n通訊內容給Google或LINE這些資訊服務業者，若不同意就不能使用服務。然\n而，業者也因此得以持續使用源源不絕的個資。」根據這段文字，下列關於\n個資蒐集或處理的敘述，何者最恰當？", "options": ["使用者交付行蹤與通訊內容是為了讓業者蒐集個資", "Google與LINE的安全機制可以有效防止個資外流", "「當事人同意」及「用於特定目的」讓業者可合法處理個資", "「個人資料保護法」規定若不同意交付個資就不能使用服務"], "correct_answer": 2, "correct_answer_json": null, "parent_question_id": null, "media": null, "source": "official", "source_meta": {"parser_version": "cap_v0.1", "merger_version": "cap_merger_v0.2", "parsed_at": "2026-04-25T19:26:39+00:00", "source_pdf_sha1": "17ed74d9cea4", "answer_pdf_sha1": "64e8d2b7d3a1", "flags": [], "parse_confidence": 1.0, "original_question_number": 14, "raw_text": "14. 「『個人資料保護法』強調，須經當事人同意才能蒐集與處理其個資，而且\n    僅能用於特定目的。眾人為使用地圖導航或方便聯繫，只能同意交付行蹤與\n    通訊內容給Google或LINE這些資訊服務業者，若不同意就不能使用服務。然\n    而，業者也因此得以持續使用源源不絕的個資。」根據這段文字，下列關於\n    個資蒐集或處理的敘述，何者最恰當？\n    (A)使用者交付行蹤與通訊內容是為了讓業者蒐集個資\n    (B)Google與LINE的安全機制可以有效防止個資外流\n    (C)「當事人同意」及「用於特定目的」讓業者可合法處理個資\n    (D)「個人資料保護法」規定若不同意交付個資就不能使用服務\n"}, "is_active": true, "auto_gradable": true, "difficulty": 3, "explanation": null}]'::jsonb) AS t(
